+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?|\
/g, '\
');
+}
+
+function trimLines(lines: string[], trimLeadingWhitespace: boolean): string[] {
+  if (!trimLeadingWhitespace) return lines;
+  return lines.map((line, index) => (index === 0 ? line : line.replace(/^\\s+/, '')));
+}
+
+function isInternal(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']): boolean {
+  const node = line.includes('node:internal');
+  const superjson = /src\\/(?:transformer|plainer|index)\\.ts/.test(line);
+  return (mode === 'node' && node) ||
+    (mode === 'superjson' && superjson) ||
+    (mode === 'node_and_superjson' && (node || superjson));
+}
+
+function redactLine(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'none') return line;
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replaceAll(cwd, '');
+  }
+  return line.replace(/(?:[A-Za-z]:)?[\\\\/][^\\s():]+/g, path => {
+    const pieces = path.split(/[\\\\/]/);
+    return pieces[pieces.length - 1] || path;
+  });
+}
+
+function processLines(
+  stack: string,
+  options: NormalizedErrorStackOptions,
+  frames: boolean
+): string[] {
+  const source = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  let lines = trimLines(source.split(/\\r\
?|\
/), options.trimLeadingWhitespace);
+  if (frames) {
+    lines = lines.filter((line, index) => index === 0 || !isInternal(line, options.stripInternalFrames));
+    lines = lines.map(line => redactLine(line, options.redactPaths));
+  } else {
+    lines = lines.map(line => redactLine(line, options.redactPaths));
+    if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+    lines = lines.filter((line, index) => index === 0 || !isInternal(line, options.stripInternalFrames));
+    return lines;
+  }
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  return lines;
+}
+
+export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
+  return processLines(stack, options, false).join('\
');
+}
+
+export function processStackFrames(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): Array<{ raw: string }> {
+  return processLines(stack, options, true).map(raw => ({ raw }));
+}
